17→void ULFPTownWidget::Setup(const TArray<ELFPTownBuildingType>& AvailableBuildings)
18→{
19→	// 先全部隐藏
20→	HideAllBuildings();
21→
22→	// 根据城镇配置显示对应建筑
23→	for (ELFPTownBuildingType Type : AvailableBuildings)
24→	{
25→		switch (Type)
26→		{
27→		case ELFPTownBuildingType::TBT_Shop:
28→			if (Button_Shop) Button_Shop->SetVisibility(ESlateVisibility::Visible);
29→			break;
30→		case ELFPTownBuildingType::TBT_EvolutionTower:
31→			if (Button_EvolutionTower) Button_EvolutionTower->SetVisibility(ESlateVisibility::Visible);
32→			break;
33→		case ELFPTownBuildingType::TBT_Teleport:
34→			if (Button_Teleport) Button_Teleport->SetVisibility(ESlateVisibility::Visible);
35→			break;
36→		case ELFPTownBuildingType::TBT_QuestNPC:
37→			if (Button_QuestNPC) Button_QuestNPC->SetVisibility(ESlateVisibility::Visible);
38→			break;
39→		case ELFPTownBuildingType::TBT_SkillNode:
40→			if (Button_SkillNode) Button_SkillNode->SetVisibility(ESlateVisibility::Visible);
41→			break;
42→		default:
43→			break;
44→		}
45→	}
46→}
