124→// ============== 输入处理 ==============
125→
126→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
127→{
128→	bIsDragging = false;
129→	if (DragTime > DragThresholdTime)
130→	{
131→		DragTime = 0.f;
132→		return;
133→	}
134→	DragTime = 0.f;
135→
136→	// 编辑器模式优先处理
137→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
138→	{
139→		// 射线检测点击的节点
140→		FHitResult HitResult;
141→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
142→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
143→
144→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
145→
146→		switch (CurrentTool)
147→		{
148→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
149→			{
150→				// 射线投射到 Z=0 平面获取世界坐标
151→				FVector WorldOrigin, WorldDirection;
152→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
153→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
154→				{
155→					float T = -WorldOrigin.Z / WorldDirection.Z;
156→					FVector HitPoint = WorldOrigin + WorldDirection * T;
157→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
158→				}
159→			}
160→			break;
161→
162→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
163→			if (ClickedNode)
164→			{
165→				WorldMapEditorComponent->SelectNode(ClickedNode);
166→				WorldMapEditorComponent->RemoveSelectedNode();
167→			}
168→			break;
169→
170→		case ELFPWorldMapEditorTool::WMET_MoveNode:
171→			if (ClickedNode)
172→			{
173→				WorldMapEditorComponent->SelectNode(ClickedNode);
174→			}
175→			else if (WorldMapEditorComponent->GetSelectedNode())
176→			{
177→				// 移动到点击位置
178→				FVector WorldOrigin, WorldDirection;
179→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
180→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
181→				{
182→					float T = -WorldOrigin.Z / WorldDirection.Z;
183→					FVector HitPoint = WorldOrigin + WorldDirection * T;
184→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
185→				}
186→			}
187→			break;
188→
189→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
190→			if (ClickedNode)
191→			{
192→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
193→			}
194→			break;
195→
196→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
197→			if (ClickedNode)
198→			{
199→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
200→			}
201→			break;
202→
203→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
204→			if (ClickedNode)
205→			{
206→				WorldMapEditorComponent->SelectNode(ClickedNode);
207→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
208→			}
209→			break;
210→
211→		default:
212→			break;
213→		}
214→		return;
215→	}
216→
217→	// 游戏模式：棋子移动中屏蔽点击
218→	ALFPWorldMapManager* Manager = GetWorldMapManager();
219→	if (Manager && Manager->IsPawnMoving()) return;
220→
221→	// 游戏模式：点击节点移动或进入
222→	FHitResult HitResult;
223→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
224→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
225→
226→	if (ClickedNode)
227→	{
228→		if (!Manager || !Manager->GetPlayerState()) return;
229→
230→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
231→
232→		// 点击当前节点 → 进入节点
233→		if (ClickedNode->NodeID == CurrentNodeID)
234→		{
235→			EnterNode(ClickedNode);
236→			return;
237→		}
238→
239→		// 点击相邻可达节点 → 移动
240→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
241→		if (ReachableIDs.Contains(ClickedNode->NodeID))
242→		{
243→			MoveToNode(ClickedNode);
244→		}
245→		else
246→		{
247→			// 不可达，只选中
248→			SelectNode(ClickedNode);
249→		}
250→	}
251→}
