432→		break;
433→
434→	case ELFPWorldNodeType::WNT_Event:
435→		// TODO: 触发事件系统
436→		UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
437→		break;
438→
439→	case ELFPWorldNodeType::WNT_Shop:
440→		// TODO: 打开商店 UI
441→		UE_LOG(LogTemp, Log, TEXT("商店节点 %d"), Node->NodeID);
442→		break;
443→
444→	case ELFPWorldNodeType::WNT_Town:
445→		OpenTown(Node);
446→		break;
447→
448→	case ELFPWorldNodeType::WNT_QuestNPC:
