409→TArray<ULFPSkillBase*> ULFPSkillSelectionWidget::GetFilteredSkills(ALFPTacticsUnit* Unit) const
410→{
411→    TArray<ULFPSkillBase*> FilteredSkills;
412→
413→    if (!Unit) return FilteredSkills;
414→
415→    // 获取所有可用技能
416→    TArray<ULFPSkillBase*> AllSkills = Unit->GetAvailableSkills();
417→
418→    // 如果没有过滤条件，返回所有技能
419→    if (SkillFilterTags.IsEmpty())
420→    {
421→        return AllSkills;
422→    }
423→
424→    // 应用过滤条件
425→    for (ULFPSkillBase* Skill : AllSkills)
426→    {
427→        if (Skill && Skill->SkillTags.HasAny(SkillFilterTags))
428→        {
429→            FilteredSkills.Add(Skill);
430→        }
431→    }
432→
433→    return FilteredSkills;
434→}
