446→void ULFPSkillSelectionWidget::SortSkills(ESkillSortMethod SortMethod)
447→{
448→    if (!OwnerUnit) return;
449→
450→    // 获取当前显示的技能
451→    TArray<ULFPSkillBase*> CurrentSkills;
452→    for (ULFPSkillButtonWidget* Button : SkillButtons)
453→    {
454→        if (Button && Button->GetSkill())
455→        {
456→            CurrentSkills.Add(Button->GetSkill());
457→        }
458→    }
459→
460→    // 根据排序方法排序
461→    switch (SortMethod)
462→    {
463→    case ESkillSortMethod::ByName:
464→        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
465→            return A.SkillName.ToString() < B.SkillName.ToString();
466→            });
467→        break;
468→
469→    case ESkillSortMethod::ByCooldown:
470→        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
471→            return A.CurrentCooldown < B.CurrentCooldown;
472→            });
473→        break;
474→
475→    case ESkillSortMethod::ByCost:
476→        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
477→            return A.ActionPointCost < B.ActionPointCost;
478→            });
479→        break;
480→
481→    case ESkillSortMethod::ByType:
482→        // 需要添加技能类型属性，如SkillType字段
483→        // CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
484→        //     return A.SkillType < B.SkillType;
485→        // });
486→        break;
487→    }
488→
489→    // 重新排列所有技能按钮
490→    if (SkillGrid)
491→    {
492→        SkillGrid->ClearChildren();
493→
494→        int32 Row = 0;
495→        int32 Column = 0;
496→
497→        for (ULFPSkillBase* Skill : CurrentSkills)
498→        {
499→            // 找到对应的按钮
500→            for (ULFPSkillButtonWidget* Button : SkillButtons)
501→            {
502→                if (Button && Button->GetSkill() == Skill)
503→                {
504→                    SkillGrid->AddChildToUniformGrid(Button, Row, Column);
505→
506→                    Column++;
507→                    if (Column >= MaxColumns)
508→                    {
509→                        Column = 0;
510→                        Row++;
511→                    }
512→
513→                    break;
514→                }
515→            }
516→        }
517→    }
518→}
