168→void ULFPSkillButtonWidget::UpdateAppearance()
169→{
170→    if (!AssociatedSkill)
171→    {
172→        SetVisibility(ESlateVisibility::Hidden);
173→        return;
174→    }
175→    SetVisibility(ESlateVisibility::Visible);
176→
177→    // 更新技能名称
178→    if (SkillNameText)
179→    {
180→        SkillNameText->SetText(AssociatedSkill->SkillName);
181→        //SkillNameText->SetVisibility(ESlateVisibility::HitTestInvisible);
182→    }
183→
184→    // 更新技能图标
185→    if (SkillIcon && AssociatedSkill->SkillIcon)
186→    {
187→        SkillIcon->SetBrushFromTexture(AssociatedSkill->SkillIcon);
188→        SkillIcon->SetVisibility(ESlateVisibility::HitTestInvisible);
189→    }
190→    else if (SkillIcon)
191→    {
192→        SkillIcon->SetVisibility(ESlateVisibility::Collapsed);
193→    }
194→
195→    // 更新冷却显示
196→    UpdateCooldownDisplay();
197→
198→    // 更新消耗显示
199→    if (CostText)
200→    {
201→        FString CostString = FString::Printf(TEXT("%d AP"), AssociatedSkill->ActionPointCost);
202→        CostText->SetText(FText::FromString(CostString));
203→        CostText->SetVisibility(ESlateVisibility::HitTestInvisible);
204→    }
205→
206→    // 更新按钮可用状态
207→    //bool bCanExecute = AssociatedSkill->CanExecute(nullptr); // 传入nullptr，因为我们不检查具体单位
208→    //SetButtonEnabled(bCanExecute);
209→    SetButtonEnabled(true);
210→}
