324→void ULFPUnitMergeWidget::OnEvolutionChoiceClicked()
325→{
326→	for (const auto& Pair : EvolutionButtonToTargetMap)
327→	{
328→		if (Pair.Key && Pair.Key->IsHovered())
329→		{
330→			SelectedEvolutionTarget = Pair.Value;
331→
332→			// 更新所有分支按钮样式：选中的三态一致，未选中的恢复 hover/press 效果
333→			for (const auto& BtnPair : EvolutionButtonToTargetMap)
334→			{
335→				UButton* Btn = BtnPair.Key;
336→				if (!Btn) continue;
337→
338→				FLFPUnitRegistryEntry Entry;
339→				if (!CachedRegistry || !CachedRegistry->FindEntry(BtnPair.Value, Entry) || !Entry.Icon) continue;
340→
341→				FButtonStyle Style = Btn->GetStyle();
342→				if (Btn == Pair.Key)
343→				{
344→					// 选中：三态一致，看起来像静态图片
345→					Style.Normal = Style.Hovered;
346→					Style.Pressed = Style.Hovered;
347→				}
348→				else
349→				{
350→					// 未选中：恢复正常交互样式
351→					Style.Normal.SetResourceObject(Entry.Icon);
352→					Style.Normal.ImageSize = Style.Hovered.ImageSize;
353→					Style.Pressed.SetResourceObject(Entry.Icon);
354→					Style.Pressed.ImageSize = Style.Hovered.ImageSize;
355→				}
356→				Btn->SetStyle(Style);
357→				Btn->SetRenderOpacity(Btn == Pair.Key ? 1.f : 0.4f);
358→			}
359→
360→			FLFPUnitRegistryEntry TargetEntry;
361→			if (CachedRegistry && CachedRegistry->FindEntry(SelectedEvolutionTarget, TargetEntry))
362→			{
363→				if (Text_PreviewName)
364→				{
365→					FString PreviewText = FString::Printf(TEXT("%s %s"),
366→						*TargetEntry.DisplayName.ToString(), *MakeTierStars(TargetEntry.Tier));
367→					Text_PreviewName->SetText(FText::FromString(PreviewText));
368→				}
369→			}
370→
371→			if (Button_Merge)
372→			{
373→				Button_Merge->SetIsEnabled(true);
374→			}
375→			return;
376→		}
377→	}
378→}
