 13→void ALFPTurnGameMode::StartPlay()
 14→{
 15→    // 从 GameInstance 读取战斗请求
 16→    if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
 17→    {
 18→        CachedBattleRequest = GI->ConsumeBattleRequest();
 19→        if (CachedBattleRequest.bIsValid)
 20→        {
 21→            UE_LOG(LogTemp, Log, TEXT("战斗模式: 由世界地图触发，节点 %d, 地图 %s, 星级 %d"),
 22→                CachedBattleRequest.SourceNodeID,
 23→                *CachedBattleRequest.BattleMapName,
 24→                CachedBattleRequest.StarRating);
 25→        }
 26→    }
 27→
 28→    FActorSpawnParameters SpawnParams;
 29→    SpawnParams.Owner = this;
 30→
 31→    // 生成网格管理器
 32→    if (GridManagerClass)
 33→    {
 34→        GridManager = GetWorld()->SpawnActor<ALFPHexGridManager>(
 35→            GridManagerClass, FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 36→    }
 37→    else
 38→    {
 39→        GridManager = GetWorld()->SpawnActor<ALFPHexGridManager>(
 40→            ALFPHexGridManager::StaticClass(), FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 41→    }
 42→
 43→    // 如果有 BattleMapName，从 CSV 加载地图
 44→    if (GridManager && !CachedBattleRequest.BattleMapName.IsEmpty())
 45→    {
 46→        FString CSVPath = FPaths::ProjectSavedDir() / TEXT("Maps") / CachedBattleRequest.BattleMapName + TEXT(".csv");
 47→        if (GridManager->LoadMapFromCSV(CSVPath))
 48→        {
 49→            UE_LOG(LogTemp, Log, TEXT("战斗模式: 从 CSV 加载地图 %s"), *CachedBattleRequest.BattleMapName);
 50→        }
 51→        else
 52→        {
 53→            UE_LOG(LogTemp, Warning, TEXT("战斗模式: CSV 地图加载失败 %s"), *CSVPath);
 54→        }
 55→    }
 56→
 57→    // 生成回合管理器
 58→    TurnManager = GetWorld()->SpawnActor<ALFPTurnManager>(
 59→        ALFPTurnManager::StaticClass(), FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 60→
 61→    if (TurnManager)
 62→    {
 63→        TurnManager->StartGame();
 64→    }
 65→
 66→    Super::StartPlay();
 67→}
 68→
 69→void ALFPTurnGameMode::EndBattle(bool bVictory, bool bEscaped)
 70→{
 71→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 72→    if (!GI) return;
 73→
 74→    // 构建战斗结果
 75→    FLFPBattleResult Result;
 76→    Result.SourceNodeID = CachedBattleRequest.SourceNodeID;
 77→    Result.bVictory = bVictory;
 78→    Result.bEscaped = bEscaped;
 79→
 80→    if (bVictory)
 81→    {
 82→        Result.CapturedUnits = CapturedUnits;
 83→        // 总奖励 = 基础奖励 + 击杀掉落
 84→        Result.GoldReward = CachedBattleRequest.BaseGoldReward + AccumulatedDropGold;
 85→        Result.FoodReward = CachedBattleRequest.BaseFoodReward + AccumulatedDropFood;
 86→    }
 87→    // 逃跑或失败：不给奖励（默认 0）
 88→
 89→    // 缓存结果，确认后写回
 90→    CachedBattleResult = Result;
 91→
 92→    // 显示结算 UI
 93→    if (BattleResultWidgetClass)
 94→    {
 95→        APlayerController* PC = GetWorld()->GetFirstPlayerController();
 96→        if (PC)
 97→        {
 98→            BattleResultWidget = CreateWidget<ULFPBattleResultWidget>(PC, BattleResultWidgetClass);
 99→            if (BattleResultWidget)
100→            {
101→                BattleResultWidget->Setup(Result, GI->UnitRegistry);
102→                BattleResultWidget->OnConfirmPressed.AddDynamic(this, &ALFPTurnGameMode::OnBattleResultConfirmed);
103→                BattleResultWidget->AddToViewport(100);
104→
105→                // 切换到 UI 输入模式
106→                FInputModeUIOnly InputMode;
107→                InputMode.SetWidgetToFocus(BattleResultWidget->TakeWidget());
108→                PC->SetInputMode(InputMode);
109→                PC->SetShowMouseCursor(true);
110→            }
111→        }
112→    }
113→    else
114→    {
115→        // 无 Widget 类配置，直接返回（兼容测试场景）
116→        OnBattleResultConfirmed();
117→    }
118→}
