1092→void ALFPTacticsPlayerController::PlaceUnit(ALFPHexTile* Tile)
1093→{
1094→    if (!Tile || !PlacingUnitPreview || PlacingPartyIndex < 0) return;
1095→
1096→    // 放置到格子上
1097→    FVector TileLocation = Tile->GetActorLocation() + FVector(0, 0, 50.f);
1098→    PlacingUnitPreview->SetActorLocation(TileLocation);
1099→    PlacingUnitPreview->SetCurrentCoordinates(Tile->GetCoordinates());
1100→
1101→    // 更新格子占用
1102→    Tile->SetIsOccupied(true);
1103→    Tile->SetUnitOnTile(PlacingUnitPreview);
1104→
1105→    // 记录到已布置列表
1106→    if (DeployedUnits.IsValidIndex(PlacingPartyIndex))
1107→    {
1108→        DeployedUnits[PlacingPartyIndex] = PlacingUnitPreview;
1109→    }
1110→
1111→    // 更新 UI
1112→    if (DeploymentWidget)
1113→    {
1114→        DeploymentWidget->MarkUnitPlaced(PlacingPartyIndex, true);
1115→    }
1116→
1117→    UE_LOG(LogTemp, Log, TEXT("放置单位到格子 (%d, %d)"), Tile->GetCoordinates().Q, Tile->GetCoordinates().R);
1118→
1119→    // 重置放置状态
1120→    PlacingUnitPreview = nullptr;
1121→    PlacingPartyIndex = -1;
1122→    bIsPlacingUnit = false;
1123→}
