 946→
 947→    switch (NewPhase)
 948→    {
 949→    case EBattlePhase::BP_Deployment:
 950→        OnDeploymentPhaseStarted();
 951→        break;
 952→
 953→    case EBattlePhase::BP_EnemyPlanning:
