 955→        HideSkillSelection();
 956→        break;
 957→
 958→    case EBattlePhase::BP_ActionPhase:
 959→        // 行动阶段：恢复正常
 960→        break;
 961→
 962→    case EBattlePhase::BP_RoundEnd:
 963→        break;
 964→    }
 965→}
